export type BnGovernanceDetectorId =
  | 'personName'
  | 'email'
  | 'phone'
  | 'postalAddress'
  | 'geoCoordinates'
  | 'companyName'
  | 'url'
  | 'ipv4'
  | 'ipv6'
  | 'creditCard'
  | 'iban'
  | 'taxVatId'
  | 'passportId'
  | 'licensePlate'
  | 'dateOfBirth'
  | 'customRegex';

export type BnGovernanceOverlapStrategy = 'longest' | 'priority';

export type BnGovernancePlaceholderType =
  | 'PERSON'
  | 'EMAIL'
  | 'PHONE'
  | 'ADDRESS'
  | 'GEO'
  | 'COMPANY'
  | 'URL'
  | 'IPV4'
  | 'IPV6'
  | 'CARD'
  | 'IBAN'
  | 'TAX_VAT'
  | 'PASSPORT'
  | 'LICENSE_PLATE'
  | 'DOB'
  | 'CUSTOM';

export interface BnDetectorOptions {
  enabled?: boolean;
  minConfidence?: number;
  /** Custom regex pattern — used by customRegex detector. */
  pattern?: string;
  flags?: string;
  label?: string;
}

export interface BnGovernanceMappingStore {
  save(mapping: BnGovernanceMapping): void;
  get(id: string): BnGovernanceMapping | undefined;
  delete(id: string): void;
  clearExpiredMappings(referenceDate?: Date): number;
  listIds(): string[];
}

export interface BnGovernanceConfig {
  detectors: Partial<Record<BnGovernanceDetectorId, boolean | BnDetectorOptions>>;
  maskChar?: string;
  /** @deprecated Use placeholderFormat instead. */
  placeholderTemplate?: string;
  placeholderFormat?: string;
  reusePlaceholders?: boolean;
  mappingTtlMs?: number;
  mappingStore?: BnGovernanceMappingStore;
  overlapStrategy?: BnGovernanceOverlapStrategy;
}

export interface BnGovernanceFinding {
  id: string;
  type: BnGovernanceDetectorId | string;
  start: number;
  end: number;
  value: string;
  confidence: number;
  placeholder?: string;
}

export interface BnGovernanceMappingMeta {
  createdAt: string;
  expiresAt?: string;
  detectorIds: (BnGovernanceDetectorId | string)[];
  placeholderFormat: string;
}

export interface BnGovernanceMapping {
  id: string;
  placeholders: Record<string, string>;
  meta: BnGovernanceMappingMeta;
}

export interface BnGovernanceResult {
  text: string;
  /** @deprecated Use text instead. Kept for backward compatibility. */
  output: string;
  findings: BnGovernanceFinding[];
  mapping: BnGovernanceMapping;
  placeholderFormat: string;
  createdAt: string;
  expiresAt?: string;
}

export interface BnGovernanceOutboundResult extends BnGovernanceResult {
  /** Sanitized user prompt with governance rules appended — ready to send to an LLM. */
  outbound: string;
}

/** Default token-handling rules appended to outbound user prompts. */
export const BN_GOVERNANCE_DEFAULT_LLM_RULES = `- Keep all [[BNM_...]] placeholder tokens exactly as provided (e.g. [[BNM_EMAIL_...]], [[BNM_PHONE_...]], [[BNM_URL_...]], [[BNM_CARD_...]], [[BNM_ADDRESS_...]], [[BNM_GEO_...]]).
- When mentioning sensitive values in replies, repeat those tokens verbatim.
- Do not invent, replace, decode, or remove placeholder tokens.`;

export interface BnGovernanceDetector {
  id: BnGovernanceDetectorId | string;
  priority: number;
  detect(input: string, options?: BnDetectorOptions): BnGovernanceFinding[];
  validate?(value: string): boolean;
}

export interface BnGovernanceDetectorDef {
  id: BnGovernanceDetectorId | string;
  priority?: number;
  pattern?: RegExp;
  validate?: (value: string) => boolean;
  confidence?: number;
  detect?: (input: string, options?: BnDetectorOptions) => BnGovernanceFinding[];
}

export interface BnGovernanceRestoreOptions {
  store?: BnGovernanceMappingStore;
}

